  9→function extractExcerpt(previewText, maxLen = 120) {
 10→    if (!previewText) return '';
 11→    const trimmed = previewText.replace(/\s+/g, ' ').trim();
 12→    if (trimmed.length <= maxLen) return trimmed;
 13→    return trimmed.slice(0, maxLen).replace(/\s+\S*$/, '') + '…';
 14→}
